import{_ as s,o as a,c as t,a0 as i}from"./chunks/framework.CWk8AOcY.js";const u=JSON.parse('{"title":"Development Environment (QEMU VM)","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/dev-environment.md","filePath":"guide/dev-environment.md"}'),n={name:"en/guide/dev-environment.md"};function o(l,e,d,h,r,p){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="development-environment-qemu-vm" tabindex="-1">Development Environment (QEMU VM) <a class="header-anchor" href="#development-environment-qemu-vm" aria-label="Permalink to &quot;Development Environment (QEMU VM)&quot;">​</a></h1><p>If you only have a laptop or a cloud VM — not a dedicated bare-metal server — but you still want to try Cube Sandbox or hack on it, you can run Cube Sandbox <strong>inside a disposable OpenCloudOS 9 virtual machine</strong> on your host.</p><p>The <code>dev-env/</code> directory at the repository root scripts the whole flow: one-off image preparation, VM boot, and auto-login.</p><p>Three commands and you have a working Cube Sandbox playground.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>The scripts in this guide must run on one of the following hosts:</p><ul><li><strong>WSL 2 on Windows</strong> (requires Windows 11 22H2+ with WSL nested virtualization enabled)</li><li><strong>A Linux physical machine</strong></li><li><strong>A Linux VM with nested virtualization enabled</strong> (cloud VM or local VM both work)</li></ul><p>In all three cases, the host must be able to use KVM — <code>/dev/kvm</code> must exist and be read/writable.</p><p>Cube Sandbox runs another layer of KVM MicroVMs inside the guest, so the host <strong>must</strong> support nested virtualization — otherwise the guest will have no usable <code>/dev/kvm</code> and sandbox creation will fail.</p><p>For detailed software dependencies and how to verify / enable nested KVM, see the &quot;Host self-check&quot; section further down.</p><h2 id="quick-start" tabindex="-1">Quick start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick start&quot;">​</a></h2><p>Clone the repository and enter <code>dev-env/</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/tencentcloud/CubeSandbox.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CubeSandbox/dev-env</span></span></code></pre></div><p>Three commands total. The first two run in one terminal, the third in a <strong>second terminal</strong>.</p><h3 id="step-1-prepare-the-image-one-off" tabindex="-1">Step 1: Prepare the image (one-off) <a class="header-anchor" href="#step-1-prepare-the-image-one-off" aria-label="Permalink to &quot;Step 1: Prepare the image (one-off)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./prepare_image.sh</span></span></code></pre></div><p>This downloads the official OpenCloudOS 9 qcow2 from the Tencent mirror and runs initialisation.</p><p>You only need to run this once per fresh image — or again after deleting the generated <code>.workdir/</code> directory.</p><h3 id="step-2-boot-the-vm" tabindex="-1">Step 2: Boot the VM <a class="header-anchor" href="#step-2-boot-the-vm" aria-label="Permalink to &quot;Step 2: Boot the VM&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./run_vm.sh</span></span></code></pre></div><p>The QEMU serial console is attached to the current terminal. Press <code>Ctrl+a</code> then <code>x</code> to power the VM off.</p><h3 id="step-3-log-in-in-a-new-terminal" tabindex="-1">Step 3: Log in (in a new terminal) <a class="header-anchor" href="#step-3-log-in-in-a-new-terminal" aria-label="Permalink to &quot;Step 3: Log in (in a new terminal)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./login.sh</span></span></code></pre></div><p><code>login.sh</code> logs you into the VM as root — Cube Sandbox&#39;s installer requires root.</p><h3 id="install-cube-sandbox-inside-the-vm" tabindex="-1">Install Cube Sandbox inside the VM <a class="header-anchor" href="#install-cube-sandbox-inside-the-vm" aria-label="Permalink to &quot;Install Cube Sandbox inside the VM&quot;">​</a></h3><p>Once you are in the root shell, run the standard one-click installer:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/tencentcloud/CubeSandbox/raw/master/deploy/one-click/online-install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Use the Tencent Cloud mirror from China</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://cnb.cool/CubeSandbox/CubeSandbox/-/git/raw/master/deploy/one-click/online-install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> MIRROR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">cn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div></div><p>When the installer finishes, follow the regular <a href="./quickstart.html">Quick Start</a> to create a template and run your first sandbox in the VM.</p><hr><p>Everything below is supplementary material and troubleshooting — you can skip it if the happy path above worked.</p><h2 id="when-to-use-this" tabindex="-1">When to use this <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to use this&quot;">​</a></h2><ul><li>You want a clean OpenCloudOS 9 environment to try Cube Sandbox.</li><li>You only have a laptop or cloud VM with KVM and nested virtualization, not a physical server.</li><li>You want to iterate on Cube Sandbox without polluting your host.</li></ul><div class="warning custom-block"><p class="custom-block-title">Not a production deployment method</p><p>This is explicitly a <strong>development / evaluation</strong> environment. For production, use <a href="./quickstart.html">Quick Start</a> or <a href="./multi-node-deploy.html">Multi-Node Cluster</a> on bare metal.</p></div><h2 id="host-self-check" tabindex="-1">Host self-check <a class="header-anchor" href="#host-self-check" aria-label="Permalink to &quot;Host self-check&quot;">​</a></h2><p>Software dependencies required on the host:</p><ul><li>Linux x86_64 with KVM enabled (<code>/dev/kvm</code> exists)</li><li>Nested virtualization enabled</li><li><code>qemu-system-x86_64</code>, <code>qemu-img</code>, <code>curl</code>, <code>ssh</code>, <code>scp</code>, <code>setsid</code></li></ul><p>Quick sanity check:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/kvm</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Intel</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/module/kvm_intel/parameters/nested</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># AMD</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/module/kvm_amd/parameters/nested</span></span></code></pre></div><p>If the <code>nested</code> parameter reads <code>N</code> or <code>0</code>, enable it on the host before continuing. Example for Intel:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;options kvm_intel nested=1&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tee</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/modprobe.d/kvm.conf</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modprobe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kvm_intel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modprobe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kvm_intel</span></span></code></pre></div><h2 id="host-↔-guest-port-map" tabindex="-1">Host ↔ guest port map <a class="header-anchor" href="#host-↔-guest-port-map" aria-label="Permalink to &quot;Host ↔ guest port map&quot;">​</a></h2><p><code>run_vm.sh</code> configures these forwards automatically:</p><table tabindex="0"><thead><tr><th>Host</th><th>Guest</th><th>Purpose</th></tr></thead><tbody><tr><td><code>127.0.0.1:10022</code></td><td><code>:22</code></td><td>SSH into the dev VM</td></tr><tr><td><code>127.0.0.1:13000</code></td><td><code>:3000</code></td><td>Cube Sandbox E2B-compatible API</td></tr></tbody></table><h2 id="what-prepare-image-sh-does-inside-the-guest" tabindex="-1">What prepare_image.sh does inside the guest <a class="header-anchor" href="#what-prepare-image-sh-does-inside-the-guest" aria-label="Permalink to &quot;What prepare_image.sh does inside the guest&quot;">​</a></h2><ul><li>Grow the root partition and filesystem to use the full 100 GB disk.</li><li>Flip SELinux to <code>permissive</code> (both at runtime and in <code>/etc/selinux/config</code>). Cube Sandbox&#39;s MySQL container bind-mounts <code>/docker-entrypoint-initdb.d</code> from the host; with enforcing SELinux and <code>container-selinux</code> policies in place, the container process gets denied and MySQL keeps restarting.</li><li>Ensure <code>/usr/local/{sbin,bin}</code> are on the login <code>PATH</code> <strong>and</strong> on sudo&#39;s <code>secure_path</code>, so <code>cubemastercli</code> and friends work both from a login shell and from <code>sudo</code>.</li><li>Install a welcome banner at <code>/etc/profile.d/cubesandbox-banner.sh</code>, so every login shell greets you with <code>Welcome to the Cube Sandbox development environment!</code>.</li></ul><h2 id="common-overrides" tabindex="-1">Common overrides <a class="header-anchor" href="#common-overrides" aria-label="Permalink to &quot;Common overrides&quot;">​</a></h2><p>All three scripts accept environment variables:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Download + resize only, skip the in-guest auto-grow workflow.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AUTO_BOOT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./prepare_image.sh</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Boot with more resources, or change the forwarded Cube API port.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VM_MEMORY_MB</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">16384</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> VM_CPUS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CUBE_API_PORT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">23000</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./run_vm.sh</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Boot without requiring nested KVM (OS will boot but sandboxes won&#39;t run).</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">REQUIRE_NESTED_KVM</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./run_vm.sh</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Log in as the regular user instead of root.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">LOGIN_AS_ROOT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./login.sh</span></span></code></pre></div><p>Defaults for <code>run_vm.sh</code>: 4 CPUs, 8192 MB RAM, SSH forwarded on <code>127.0.0.1:10022</code>, Cube API forwarded on <code>127.0.0.1:13000</code> (guest <code>:3000</code>).</p><h2 id="reset-clean-up" tabindex="-1">Reset / clean up <a class="header-anchor" href="#reset-clean-up" aria-label="Permalink to &quot;Reset / clean up&quot;">​</a></h2><ul><li>To reset the VM state, stop any running <code>run_vm.sh</code>, delete <code>dev-env/.workdir/</code>, then run <code>./prepare_image.sh</code> again.</li><li>The dev VM is disposable by design. You are expected to rebuild it whenever the installed state becomes unusable.</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Likely cause</th><th>Fix</th></tr></thead><tbody><tr><td>No <code>/dev/kvm</code> inside the guest</td><td>Host does not have nested KVM enabled</td><td>Enable nested virtualization on the host and reboot the VM</td></tr><tr><td><code>./login.sh</code> cannot connect</td><td>VM not booted yet, or host port <code>10022</code> is busy</td><td>Confirm <code>./run_vm.sh</code> is still running; or change <code>SSH_PORT</code></td></tr><tr><td><code>cube-sandbox-mysql</code> keeps restarting with <code>Permission denied</code></td><td>Guest SELinux is still enforcing</td><td>Re-run <code>./prepare_image.sh</code>, or inside the guest: <code>setenforce 0 &amp;&amp; sed -i &#39;s/^SELINUX=enforcing/SELINUX=permissive/&#39; /etc/selinux/config &amp;&amp; docker restart cube-sandbox-mysql</code></td></tr><tr><td><code>df -h /</code> inside the guest is still small</td><td>The auto-grow step did not complete</td><td>Inspect <code>.workdir/qemu-serial.log</code>, then <code>scp internal/grow_rootfs.sh</code> into the guest and run it manually</td></tr><tr><td>Host port <code>13000</code> is already taken</td><td>Another service is bound to <code>13000</code></td><td>Use <code>CUBE_API_PORT=23000 ./run_vm.sh</code> and update <code>E2B_API_URL</code> accordingly</td></tr></tbody></table><h2 id="directory-layout" tabindex="-1">Directory layout <a class="header-anchor" href="#directory-layout" aria-label="Permalink to &quot;Directory layout&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dev-env/</span></span>
<span class="line"><span>├── prepare_image.sh   # one-off: download + resize + guest-side init</span></span>
<span class="line"><span>├── run_vm.sh          # day-to-day: boot the VM</span></span>
<span class="line"><span>├── login.sh           # day-to-day: SSH in and switch to root</span></span>
<span class="line"><span>├── internal/          # helper scripts invoked inside the guest</span></span>
<span class="line"><span>│   ├── grow_rootfs.sh</span></span>
<span class="line"><span>│   ├── setup_selinux.sh</span></span>
<span class="line"><span>│   ├── setup_path.sh</span></span>
<span class="line"><span>│   └── setup_banner.sh</span></span>
<span class="line"><span>├── README.md</span></span>
<span class="line"><span>└── README_zh.md</span></span></code></pre></div><p>For a short overview, see the <a href="https://github.com/tencentcloud/CubeSandbox/tree/master/dev-env" target="_blank" rel="noreferrer"><code>dev-env/README.md</code></a> in the repository.</p>`,57)])])}const k=s(n,[["render",o]]);export{u as __pageData,k as default};
